"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["63150"],{51482(i){i.exports=JSON.parse('{"tag":{"label":"govtech","permalink":"/sysanalyst-kb.github.io/docs/tags/govtech","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":8,"items":[{"id":"specialization/govtech-path","title":"GovTech \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C \u0432 \u0433\u043E\u0441\u0441\u0435\u043A\u0442\u043E\u0440\u0435","description":"GovTech-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438 (\u0413\u0418\u0421) \u0436\u0451\u0441\u0442\u043A\u0430\u044F \u0440\u0435\u0433\u0443\u043B\u044F\u0446\u0438\u044F (\u0424\u0421\u0422\u042D\u041A, 152-\u0424\u0417, 44-\u0424\u0417), \u0438\u043C\u043F\u043E\u0440\u0442\u043E\u0437\u0430\u043C\u0435\u0449\u0435\u043D\u0438\u0435, \u0434\u043B\u0438\u043D\u043D\u044B\u0435 \u0442\u0435\u043D\u0434\u0435\u0440\u043D\u044B\u0435 \u0446\u0438\u043A\u043B\u044B \u0438 \u0440\u0430\u0431\u043E\u0442\u0430 \u0441 \u0413\u0418\u0421-\u043E\u043F\u0435\u0440\u0430\u0442\u043E\u0440\u0430\u043C\u0438. \u0420\u044B\u043D\u043E\u043A GovTech \u0432 \u0420\u0424 \u2014 350+ \u043C\u043B\u0440\u0434 \u20BD (2024), CAGR 25%, \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u0439 \u0434\u0440\u0430\u0439\u0432\u0435\u0440 \u2014 \u0446\u0438\u0444\u0440\u043E\u0432\u0430\u044F \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044F \u0433\u043E\u0441\u0443\u0441\u043B\u0443\u0433 \u0438 \u0438\u043C\u043F\u043E\u0440\u0442\u043E\u0437\u0430\u043C\u0435\u0449\u0435\u043D\u0438\u0435.","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-path"},{"id":"specialization/govtech-gis-architecture","title":"\u0410\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u0413\u0418\u0421 \u2014 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B","description":"\u0413\u0418\u0421 (\u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430) \u2014 \u0418\u0421 \u0434\u043B\u044F \u043E\u043A\u0430\u0437\u0430\u043D\u0438\u044F \u0433\u043E\u0441\u0443\u0441\u043B\u0443\u0433, \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0433\u043E\u0441\u0444\u0443\u043D\u043A\u0446\u0438\u0439 \u0438\u043B\u0438 \u043C\u0435\u0436\u0432\u0435\u0434\u043E\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F. \u0410\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u0413\u0418\u0421 \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0415\u041F\u0413\u0423 (110M+ \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439), \u0413\u0418\u0421 \u0413\u041C\u041F (500M+ \u043F\u043B\u0430\u0442\u0435\u0436\u0435\u0439/\u0433\u043E\u0434), \u0415\u0413\u0418\u0421\u0421\u041E (100M+ \u0437\u0430\u043F\u0438\u0441\u0435\u0439).","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-gis-architecture"},{"id":"specialization/govtech-security","title":"\u0411\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u044C \u0438 \u0430\u0442\u0442\u0435\u0441\u0442\u0430\u0446\u0438\u044F (\u0424\u0421\u0422\u042D\u041A, \u043A\u0440\u0438\u043F\u0442\u043E\u0433\u0440\u0430\u0444\u0438\u044F)","description":"\u041B\u044E\u0431\u0430\u044F \u0413\u0418\u0421 \u043E\u0431\u044F\u0437\u0430\u043D\u0430 \u043F\u0440\u043E\u0439\u0442\u0438 \u0430\u0442\u0442\u0435\u0441\u0442\u0430\u0446\u0438\u044E \u043F\u043E \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F\u043C \u0424\u0421\u0422\u042D\u041A \u0420\u043E\u0441\u0441\u0438\u0438. \u0410\u0442\u0442\u0435\u0441\u0442\u0430\u0446\u0438\u044F \u0432\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0423\u0417-1 (\u041E\u041F\u0414), \u0423\u0417-2 (\u041F\u0414, \u0433\u043E\u0441\u0443\u0441\u043B\u0443\u0433\u0438), \u0423\u0417-3 (\u0432\u0435\u0434\u043E\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438: \u0438\u0434\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F (\u0415\u0421\u0418\u0410/\u0423\u041A\u042D\u041F), \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0434\u043E\u0441\u0442\u0443\u043F\u043E\u043C (RBAC), \u0430\u0443\u0434\u0438\u0442, \u0430\u043D\u0442\u0438\u0432\u0438\u0440\u0443\u0441, \u043A\u0440\u0438\u043F\u0442\u043E\u0433\u0440\u0430\u0444\u0438\u044F (\u0413\u041E\u0421\u0422).","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-security"},{"id":"specialization/govtech-procurement","title":"\u0413\u043E\u0441\u0437\u0430\u043A\u0443\u043F\u043A\u0438 \u0432 IT (44-\u0424\u0417, 223-\u0424\u0417)","description":"44-\u0424\u0417 \u2014 \u0433\u043E\u0441\u0437\u0430\u043A\u0443\u043F\u043A\u0438 \u0434\u043B\u044F \u0431\u044E\u0434\u0436\u0435\u0442\u043D\u044B\u0445 \u0443\u0447\u0440\u0435\u0436\u0434\u0435\u043D\u0438\u0439 (\u0441\u0442\u0440\u043E\u0433\u0438\u0435 \u043F\u0440\u043E\u0446\u0435\u0434\u0443\u0440\u044B, \u0430\u0443\u043A\u0446\u0438\u043E\u043D\u044B, \u043A\u043E\u043D\u043A\u0443\u0440\u0441\u044B, \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0422\u0417, \u0441\u0440\u043E\u043A\u0438 30-90 \u0434\u043D\u0435\u0439). 223-\u0424\u0417 \u2014 \u0434\u043B\u044F \u0433\u043E\u0441\u043A\u043E\u043C\u043F\u0430\u043D\u0438\u0439 (\u0433\u0438\u0431\u0447\u0435, \u0441\u0432\u043E\u0438 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044F, 15-45 \u0434\u043D\u0435\u0439). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043D\u0430 \u0441\u0442\u043E\u0440\u043E\u043D\u0435 \u0437\u0430\u043A\u0430\u0437\u0447\u0438\u043A\u0430 \u043F\u0438\u0448\u0435\u0442 \u0422\u0417, \u043E\u0431\u043E\u0441\u043D\u043E\u0432\u044B\u0432\u0430\u0435\u0442 \u041D\u041C\u0426\u041A, \u043F\u0440\u043E\u0432\u0435\u0440\u044F\u0435\u0442 \u0437\u0430\u044F\u0432\u043A\u0438. \u041D\u0430 \u0441\u0442\u043E\u0440\u043E\u043D\u0435 \u0438\u0441\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044F \u2014 \u0430\u043D\u0430\u043B\u0438\u0437\u0438\u0440\u0443\u0435\u0442 \u0422\u0417, \u043E\u0446\u0435\u043D\u0438\u0432\u0430\u0435\u0442 \u043E\u0431\u044A\u0451\u043C, \u0433\u043E\u0442\u043E\u0432\u0438\u0442 \u0442\u0435\u0445\u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0438\u0435. \u0415\u0418\u0421 (zakupki.gov.ru) \u2014 \u0435\u0434\u0438\u043D\u044B\u0439 \u043F\u043E\u0440\u0442\u0430\u043B \u0437\u0430\u043A\u0443\u043F\u043E\u043A, \u043F\u0443\u0431\u043B\u0438\u043A\u0443\u044E\u0442\u0441\u044F \u0432\u0441\u0435 \u0442\u0435\u043D\u0434\u0435\u0440\u044B. \u0420\u044B\u043D\u043E\u043A \u0433\u043E\u0441\u0437\u0430\u043A\u0443\u043F\u043E\u043A IT \u0432 \u0420\u0424 \u2014 500+ \u043C\u043B\u0440\u0434 \u20BD/\u0433\u043E\u0434.","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-procurement"},{"id":"specialization/govtech-portal","title":"\u0413\u043E\u0441\u0443\u0441\u043B\u0443\u0433\u0438 \u0438 \u043F\u043E\u0440\u0442\u0430\u043B\u044B \u2014 \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435","description":"\u041F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043F\u043E\u0440\u0442\u0430\u043B\u0430 \u0433\u043E\u0441\u0443\u0441\u043B\u0443\u0433 \u2014 \u044D\u0442\u043E \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \xab\u0444\u043E\u0440\u043C\u043E\u0447\u043A\u0430 \u0434\u043B\u044F \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u0438\u0439\xbb. \u041D\u0443\u0436\u043D\u043E \u0443\u0447\u0435\u0441\u0442\u044C \u0415\u0421\u0418\u0410 (\u0430\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044E \u0447\u0435\u0440\u0435\u0437 \u0413\u043E\u0441\u0443\u0441\u043B\u0443\u0433\u0438), \u0421\u041C\u042D\u0412 (\u043C\u0435\u0436\u0432\u0435\u0434\u043E\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0437\u0430\u043F\u0440\u043E\u0441\u044B), \u0441\u0442\u0430\u0442\u0443\u0441\u044B \u0443\u0441\u043B\u0443\u0433\u0438, \u043F\u0440\u0438\u043A\u0440\u0435\u043F\u043B\u0435\u043D\u0438\u0435 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u0432, \u044E\u0440\u0438\u0434\u0438\u0447\u0435\u0441\u043A\u0438 \u0437\u043D\u0430\u0447\u0438\u043C\u044B\u0439 \u042D\u0414\u041E, \u043E\u043F\u043B\u0430\u0442\u0443 \u0433\u043E\u0441\u043F\u043E\u0448\u043B\u0438\u043D\u044B (\u0413\u0418\u0421 \u0413\u041C\u041F) \u0438 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F 59-\u0424\u0417 (\u0441\u0440\u043E\u043A\u0438 \u043E\u0442\u0432\u0435\u0442\u0430: 30 \u0434\u043D\u0435\u0439). \u0415\u041F\u0413\u0423 (gosuslugi.ru) \u2014 110M+ \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439, 100K+ \u0443\u0441\u043B\u0443\u0433, \u043D\u0430\u0433\u0440\u0443\u0437\u043A\u0430 \u0434\u043E 10 000 \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u0438\u0439/\u0447\u0430\u0441 \u0432 \u043F\u0438\u043A\u0435.","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-portal"},{"id":"specialization/govtech-import-substitution","title":"\u0418\u043C\u043F\u043E\u0440\u0442\u043E\u0437\u0430\u043C\u0435\u0449\u0435\u043D\u0438\u0435 \u0432 IT \u0438 \u0440\u0435\u0435\u0441\u0442\u0440 \u043E\u0442\u0435\u0447\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u041F\u041E","description":"\u0418\u043C\u043F\u043E\u0440\u0442\u043E\u0437\u0430\u043C\u0435\u0449\u0435\u043D\u0438\u0435 \u2014 \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0435 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u0435 \u0434\u043B\u044F \u0413\u0418\u0421 Astra Linux Special Edition (\u041E\u0421, 80% \u0433\u043E\u0441\u043E\u0440\u0433\u0430\u043D\u043E\u0432), Postgres Pro (\u0421\u0423\u0411\u0414, 70%+), \xab\u041A\u0440\u0438\u043F\u0442\u043E\u041F\u0440\u043E CSP\xbb (\u043A\u0440\u0438\u043F\u0442\u043E\u0433\u0440\u0430\u0444\u0438\u044F, 95%+), \xab1\u0421\xbb (\u0443\u0447\u0451\u0442), \xab\u041C\u043E\u0439\u041E\u0444\u0438\u0441\xbb/\xab\u04207-\u041E\u0444\u0438\u0441\xbb (\u043E\u0444\u0438\u0441). \u0423\u043A\u0430\u0437 \u041F\u0440\u0435\u0437\u0438\u0434\u0435\u043D\u0442\u0430 \u2116 166 (2022) \u2014 \u043A\u0440\u0438\u0442\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0438\u043D\u0444\u0440\u0430\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0430 \u0434\u043E\u043B\u0436\u043D\u0430 \u043F\u0435\u0440\u0435\u0439\u0442\u0438 \u043D\u0430 \u043E\u0442\u0435\u0447\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u041F\u041E \u043A 2025. \u0420\u044B\u043D\u043E\u043A: 200+ \u043C\u043B\u0440\u0434 \u20BD (2024), 10 000+ \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u043E\u0432 \u0432 \u0440\u0435\u0435\u0441\u0442\u0440\u0435. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u0440\u043E\u0432\u0435\u0440\u0438\u0442\u044C \u043A\u0430\u0436\u0434\u044B\u0439 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u043D\u0430 \u043D\u0430\u043B\u0438\u0447\u0438\u0435 \u0432 \u0440\u0435\u0435\u0441\u0442\u0440\u0435 \u0438 \u0443\u0447\u0435\u0441\u0442\u044C \u044D\u0442\u043E \u0432 \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-import-substitution"},{"id":"specialization/govtech-smev","title":"\u0421\u041C\u042D\u0412 \u2014 \u043C\u0435\u0436\u0432\u0435\u0434\u043E\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0435 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435","description":"\u0421\u041C\u042D\u0412 \u2014 \xab\u0448\u0438\u043D\u0430\xbb \u0434\u043B\u044F \u043E\u0431\u043C\u0435\u043D\u0430 \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u0433\u043E\u0441\u0443\u0434\u0430\u0440\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C\u0438 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438. \u0412\u0435\u0440\u0441\u0438\u044F 3 (\u0442\u0435\u043A\u0443\u0449\u0430\u044F) \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0447\u0435\u0440\u0435\u0437 REST \u0438 JSON (\u0440\u0430\u043D\u0435\u0435 SOAP/XML). \u0427\u0435\u0440\u0435\u0437 \u0421\u041C\u042D\u0412 \u043F\u0440\u043E\u0445\u043E\u0434\u044F\u0442 1B+ \u0437\u0430\u043F\u0440\u043E\u0441\u043E\u0432/\u0433\u043E\u0434, 25 000+ \u043F\u043E\u0434\u043A\u043B\u044E\u0447\u0451\u043D\u043D\u044B\u0445 \u0413\u0418\u0421. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 5-30 \u0441\u0435\u043A), \u044E\u0440\u0438\u0434\u0438\u0447\u0435\u0441\u043A\u0443\u044E \u0437\u043D\u0430\u0447\u0438\u043C\u043E\u0441\u0442\u044C (\u0423\u041A\u042D\u041F). \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043F\u0440\u043E\u0432\u0430\u0439\u0434\u0435\u0440\u044B: \u0415\u0421\u0418\u0410 (\u0430\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F + \u043C\u0435\u0442\u0430\u0434\u0430\u043D\u043D\u044B\u0435), \u0448\u043B\u044E\u0437 \u0421\u041C\u042D\u0412 (ViPNet, \u043A\u0440\u0438\u043F\u0442\u043E\u0433\u0440\u0430\u0444\u0438\u044F).","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-smev"},{"id":"specialization/govtech-edo","title":"\u042D\u0414\u041E \u0438 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442 \u0432 \u0433\u043E\u0441\u0441\u0435\u043A\u0442\u043E\u0440\u0435","description":"\u042D\u0414\u041E (\u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u044B\u0439 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442) \u0432 \u0433\u043E\u0441\u0441\u0435\u043A\u0442\u043E\u0440\u0435 \u2014 \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u043E\u0431\u043C\u0435\u043D \u0444\u0430\u0439\u043B\u0430\u043C\u0438. \u042D\u0442\u043E \u044E\u0440\u0438\u0434\u0438\u0447\u0435\u0441\u043A\u0438 \u0437\u043D\u0430\u0447\u0438\u043C\u044B\u0439 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442 \u0441 \u0423\u041A\u042D\u041F (\u0443\u0441\u0438\u043B\u0435\u043D\u043D\u043E\u0439 \u043A\u0432\u0430\u043B\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0439 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0434\u043F\u0438\u0441\u044C\u044E \u043F\u043E \u0413\u041E\u0421\u0422 \u0420 34.10), \u0421\u041C\u042D\u0412-\u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0435\u0439, \u0430\u0440\u0445\u0438\u0432\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435\u043C (5-75 \u043B\u0435\u0442) \u0438 \u0441\u0442\u0440\u043E\u0433\u0438\u043C\u0438 \u0441\u0440\u043E\u043A\u0430\u043C\u0438 \u043F\u043E 59-\u0424\u0417 (30 \u0434\u043D\u0435\u0439). \u0422\u0438\u043F\u044B Directum, TESSA, 1\u0421:\u0414\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442, \xab\u0414\u0435\u043B\u043E\xbb. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u044B \u0441\u043E\u0433\u043B\u0430\u0441\u043E\u0432\u0430\u043D\u0438\u044F (\u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435/\u043F\u0430\u0440\u0430\u043B\u043B\u0435\u043B\u044C\u043D\u044B\u0435), \u0444\u043E\u0440\u043C\u0430\u0442 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u0432 (PDF/A, XML \u0441 \u0423\u041A\u042D\u041F) \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 \u0423\u0434\u043E\u0441\u0442\u043E\u0432\u0435\u0440\u044F\u044E\u0449\u0438\u043C \u0446\u0435\u043D\u0442\u0440\u043E\u043C.","permalink":"/sysanalyst-kb.github.io/docs/specialization/govtech-edo"}],"unlisted":false}}')}}]);